	(
		@Guid UNIQUEIDENTIFIER,
		@UserId INT
	)
RETURNS TABLE
AS
RETURN SELECT		md.RowStatus,
					md.RowVersion,
					md.Guid,
					md.Name,
					md.FilenameTemplate,
					ss.SiteIdentifier AS DriveId,
					md.DocumentId,
					e.Guid AS EntityTypeGuid,
					le.Guid AS LinkedEntityTypeGuid,
					md.AllowPDFOutputOnly,
