--
-- Create or alter procedure [SSop].[QuoteItemsUpsert]
--
GO






CREATE OR ALTER PROCEDURE [SSop].[QuoteItemsUpsert]
  (
    @QuoteGuid    UNIQUEIDENTIFIER,
    @ProductGuid         UNIQUEIDENTIFIER,
    @Details             NVARCHAR(2000),
    @Net                 DECIMAL(9, 2),
    @VatRate             DECIMAL(9, 2),
    @DoNotConsolidateJob BIT,
    @SortOrder           INT,
    @Quantity            DECIMAL(9, 2),
	@ProvidedAtStageGuid UNIQUEIDENTIFIER,
    @Guid                UNIQUEIDENTIFIER,
	@NumberOfSiteVisits		 INT,
	@NumberOfMeetings    INT
  )
AS
  BEGIN
    DECLARE @QuoteId INT,
            @ProductId      INT,
			@ProvidedAtStageId INT,
            @IsInsert       BIT;

    SELECT
            @QuoteId = ID
    FROM
            SSop.Quotes
    WHERE
            ([Guid] = @QuoteGuid)

    SELECT
            @ProvidedAtStageId = ID
    FROM
            SJob.RibaStages AS rs
    WHERE
            ([Guid] = @ProvidedAtStageGuid)

	SELECT
            @ProductId = ID
    FROM
            SProd.Products
    WHERE
            ([Guid] = @ProductGuid)

    EXEC SCore.UpsertDataObject
      @Guid       = @Guid,					-- uniqueidentifier
      @SchemeName = N'SSop',				-- nvarchar(255)
      @ObjectName = N'QuoteItems',				-- nvarchar(255)
      @IsInsert   = @IsInsert OUTPUT	-- bit

    IF (@IsInsert = 1)
      BEGIN
        INSERT SSop.QuoteItems
              (
                RowStatus,
                Guid,
                QuoteId,
                ProductId,
                Details,
                Net,
                VatRate,
                DoNotConsolidateJob,
                SortOrder,
                Quantity,
				ProvideAtStageID,
				NumberOfMeetings,
				NumberOfSiteVisits
              )
        VALUES
                (
                  1,	-- RowStatus - tinyint
                  @Guid,	-- Guid - uniqueidentifier
                  @QuoteId,	-- QuoteSectionId - int
                  @ProductId,	-- ProductId - int
                  @Details,	-- Details - nvarchar(2000)
                  @Net,	-- Net - decimal(9, 2)
                  @VatRate,	-- VatRate - decimal(9, 2)
                  @DoNotConsolidateJob,	-- DoNotConsolidateJob - bit
                  @SortOrder,	-- SortOrder - int
                  @Quantity,
				  @ProvidedAtStageId,
				  @NumberOfMeetings,
				  @NumberOfSiteVisits
                )
      END
    ELSE
      BEGIN
        UPDATE  SSop.QuoteItems
        SET     QuoteId = @QuoteId,
                ProductId = @ProductId,
                Details = @Details,
                Net = @Net,
                VatRate = @VatRate,
                DoNotConsolidateJob = @DoNotConsolidateJob,
                SortOrder = @SortOrder,
                Quantity = @Quantity,
				ProvideAtStageID = @ProvidedAtStageId,
				NumberOfMeetings = @NumberOfMeetings,
				NumberOfSiteVisits = @NumberOfSiteVisits
        WHERE
          ([Guid] = @Guid)
      END
  END
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[QuoteTemplatesCreateQuote]
--
GO



CREATE OR ALTER PROCEDURE [SSop].[QuoteTemplatesCreateQuote]
	(
		@TemplateGuid UNIQUEIDENTIFIER,
		@QuoteGuid UNIQUEIDENTIFIER,
		@UserGuid UNIQUEIDENTIFIER
	)
AS
BEGIN

	DECLARE @Overview NVARCHAR(MAX),
			@FeeCap DECIMAL(19, 2),
			@QuoteDate DATE = GETDATE()

	SELECT	@Overview = qt.Overview,
			@FeeCap = qt.FeeCap
	FROM	SSop.QuoteTemplates qt
	WHERE	(guid = @TemplateGuid)

	EXEC SSop.QuotesUpsert @OrganisationalUnitGuid = '00000000-0000-0000-0000-000000000000',	-- uniqueidentifier
						   @QuotingUserGuid = @UserGuid,			-- uniqueidentifier
						   @Number = 0,						-- int
						   @ClientAccountGuid = '00000000-0000-0000-0000-000000000000',		-- uniqueidentifier
						   @ClientAddressGuid = '00000000-0000-0000-0000-000000000000',		-- uniqueidentifier
						   @ClientContactGuid = '00000000-0000-0000-0000-000000000000',		-- uniqueidentifier
						   @AgentAccountGuid = '00000000-0000-0000-0000-000000000000',		-- uniqueidentifier
						   @AgentAddressGuid = '00000000-0000-0000-0000-000000000000',		-- uniqueidentifier
						   @AgentContactGuid = '00000000-0000-0000-0000-000000000000',		-- uniqueidentifier
						   @ContractGuid = '00000000-0000-0000-0000-000000000000',			-- uniqueidentifier
						   @Date = @QuoteDate,			-- date
						   @Overview = @Overview,					-- nvarchar(max)
						   @ExpiryDate = NULL,		-- date
						   @DateSent = NULL,		-- date
						   @DateAccepted = NULL,	-- date
						   @DateRejected = NULL,	-- date
						   @RejectionReason = N'',			-- nvarchar(max)
						   @QuoteSourceGuid = '00000000-0000-0000-0000-000000000000',			-- uniqueidentifier
						   @UprnGuid = '00000000-0000-0000-0000-000000000000',				-- uniqueidentifier
						   @ChaseDate1 = NULL,		-- date
						   @ChaseDate2 = NULL,		-- date
						   @FeeCap = @FeeCap,					-- decimal(19, 2)
						   @Guid = @QuoteGuid,						-- uniqueidentifier
						   @JobType = '00000000-0000-0000-0000-000000000000' --[CBLD-590: Defaulting to empty guid since this will be populated]



	DECLARE @MaxQuoteSection INT,
			@CurrentQuoteSection INT,
			@RibaStageGuid UNIQUEIDENTIFIER,
			@Name NVARCHAR(200),
			@SectionOverview NVARCHAR(MAX),
			@ShowProducts BIT,
			@ConsolidateJobs BIT,
			@SortOrder INT,
			@NumberOfMeetings INT,
			@NumberOfSiteVisits INT,
			@SectionGuid UNIQUEIDENTIFIER,
			@ProductGuid UNIQUEIDENTIFIER,
			@ItemDetails NVARCHAR(2000),
			@Net DECIMAL(19,2),
			@VatRate DECIMAL (19,2),
			@DoNotConsolidateJob BIT,
			@ItemSortOrder INT,
			@ItemQuantity DECIMAL(19,2),
			@ItemGuid UNIQUEIDENTIFIER,
			@MaxQuoteItem INT,
			@CurrentQuoteItem INT 


	SELECT	@MaxQuoteSection = MAX(qts.ID),
			@CurrentQuoteSection = -1
	FROM	SSop.QuoteTemplateSections qts
	JOIN	SSop.QuoteTemplates qt ON (qt.ID = qts.QuoteTemplateId)
	WHERE	(qt.Guid = @TemplateGuid)

	WHILE	(@CurrentQuoteSection < @MaxQuoteSection)
	BEGIN 
		SELECT	TOP(1) @CurrentQuoteSection = qts.ID,
			@CurrentQuoteSection = -1,
			@RibaStageGuid = rs.Guid,
			@Name = qts.Name,
			@SectionOverview = qts.Overview,
			@ShowProducts = qts.ShowProducts,
			@ConsolidateJobs = qts.ConsolidateJobs,
			@SortOrder = qts.SortOrder,
			@NumberOfMeetings = qts.NumberOfMeetings,
			@NumberOfSiteVisits = qts.NumberOfSiteVisits,
			@SectionGuid = NEWID()
		FROM	SSop.QuoteTemplateSections qts
		JOIN	SSop.QuoteTemplates qt ON (qt.ID = qts.QuoteTemplateId)
		JOIN	SJob.RibaStages rs ON (rs.ID = qts.RibaStageId)
		WHERE	(qt.Guid = @TemplateGuid)
			AND	(qts.ID > @CurrentQuoteSection)
		ORDER BY qts.ID
		
		EXECUTE SSop.QuoteSectionsUpsert @QuoteGuid = @QuoteGuid,					-- uniqueidentifier
										 @RibaStageGuid = @RibaStageGuid,				-- uniqueidentifier
										 @Name = @Name,						-- nvarchar(200)
										 @Overview = @SectionOverview,					-- nvarchar(max)
										 @ShowProducts = @ShowProducts,				-- bit
										 @ConsolidateJobs = @ConsolidateJobs,			-- bit
										 @SortOrder = @SortOrder,					-- int
										 @NumberOfMeetings = @NumberOfMeetings,				-- int
										 @NumberOfSiteVisits = @NumberOfSiteVisits,			-- int
										 @CombineWithSectionGuid = @SectionGuid,	-- uniqueidentifier
										 @Guid = @SectionGuid						-- uniqueidentifier

		SELECT	@MaxQuoteItem = MAX(qti.ID),
				@CurrentQuoteItem = -1
		FROM	SSop.QuoteTemplateItems qti
		WHERE	(qti.QuoteTemplateSectionId = @CurrentQuoteSection)

		WHILE	(@CurrentQuoteItem > @MaxQuoteItem)
		BEGIN 
			SELECT	TOP (1) @CurrentQuoteItem = qti.ID,
					@ProductGuid = p.Guid,
					@ItemDetails = qti.ID,
					@Net = qti.Net,
					@VatRate = qti.VatRate,
					@DoNotConsolidateJob = qti.DoNotConsolidateJob,
					@SortOrder = qti.SortOrder,
					@ItemQuantity = qti.Quantity
			FROM	SSop.QuoteTemplateItems qti
			JOIN	SProd.Products p ON (p.ID = qti.ProductId)
			WHERE	(qti.QuoteTemplateSectionId = @CurrentQuoteSection)
			ORDER BY qti.ID

			EXECUTE SSop.QuoteItemsUpsert @QuoteSectionGuid = @SectionGuid,		-- uniqueidentifier
										  @ProductGuid = @ProductGuid,			-- uniqueidentifier
										  @Details = @ItemDetails,				-- nvarchar(2000)
										  @Net = @Net,					-- decimal(9, 2)
										  @VatRate = @VatRate,				-- decimal(9, 2)
										  @DoNotConsolidateJob = @DoNotConsolidateJob,	-- bit
										  @SortOrder = @ItemSortOrder,				-- int
										  @Quantity = @ItemQuantity,				-- decimal(9, 2)
										  @Guid = @ItemGuid					-- uniqueidentifier
		END
		
		
	END
	
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_QuotesValidate]
--
GO


CREATE OR ALTER FUNCTION [SSop].[tvf_QuotesValidate]
	(
		@Guid UNIQUEIDENTIFIER,
		@DateSent DATE,
		@DeadDate DATE,
		@DateRejected DATE,
		@IsFinal BIT,
		@RevisionNumber INT,
		@OrganisationalUnitGuid UNIQUEIDENTIFIER,
		--[CBLD-592]
		@DateDeclinedToQuote DATE,
		@DeclinedToQuoteReason NVARCHAR(MAX)
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		IsInformationOnly BIT NOT NULL DEFAULT ((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	DECLARE @EntityTypeGuid UNIQUEIDENTIFIER = '1c4794c1-f956-4c32-b886-5500ac778a56';


	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteItems AS qi
		 JOIN	SSop.Quotes		AS q ON (q.ID = qi.QuoteId)
		 WHERE	(q.Guid			 = @Guid)
			AND (qi.RowStatus NOT IN (0, 254))
			AND (qi.CreatedJobId > 0)
	 )
	   )
	OR	(@DeadDate IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		VALUES
			 (
				 @EntityTypeGuid,
				 N'E',
				 1,
				 0,
				 0,
				 N''
			 );
	END;

	-- Hide fields from CDM based quotes 
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SCore.OrganisationalUnits AS ou
		 WHERE	(ou.Guid = @OrganisationalUnitGuid)
			AND (ou.Name LIKE N'CDM%')
	 )
	   )
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'FeeCap');
	END;

	/*IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.QuoteSections AS qs
		 JOIN	SSop.Quotes		   AS q ON (q.ID = qs.QuoteId)
		 WHERE	(q.Guid			= @Guid)
			AND (qs.RibaStageId < 0)
			AND (qs.RowStatus NOT IN (0, 254))
	 )
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				0,
				1,
				N'All sections must have a Stage set.'
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'Number');
	END;*/

	IF (@RevisionNumber < 1)
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= (N'RevisionNumber'));


	END;

	--[CBLD-592] Check if the DeclinedToQuoteDate is set & there is no reason why it's been declined.
	IF(@DateDeclinedToQuote IS NOT NULL AND @DeclinedToQuoteReason = N'')
	BEGIN
				DECLARE @EntityPropertyGuid UNIQUEIDENTIFIER;
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Quotes',
																			  N'DeclinedToQuoteReason'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'You must enter the reason why we declined to quote.'
					 );
			END;

	----[CBLD-592] Check if the DeclinedToQuoteDate is set - if it is, set IsReadOnly for the whole form.
	IF(@DateDeclinedToQuote IS NOT NULL AND @DeclinedToQuoteReason <> N'' AND NOT EXISTS(SELECT 1 FROM SSop.Quotes AS q WHERE q.Guid = @Guid AND q.DeclinedToQuoteReason = N''))
		BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')

		RETURN
	END

	/* Don't allow the user to progress the status further than Send until the quote has been marked as Sent. */
	IF (@DateSent IS NULL)
	BEGIN

		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name IN (N'DateAccepted', N'DateRejected', N'RejectionReason', N'ChaseDate1', N'ChaseDate2'));

	END;

	/* Once the quote has been sent you can't unset it as "Is Final" */
	IF (@DateSent IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'IsFinal');
	END;

	/* Don't allow the quote to be sent until it has been set as "Is Final" */
	IF (@IsFinal = 0)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'DateSent');
	END;

	/* Hide Rejection Reason if the Quote hasn't been rejected. */
	IF (@DateRejected IS NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name		= N'RejectionReason');
	END;



	IF (@IsFinal = 1)
   AND	(NOT EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	(q.Guid						= @Guid)
			AND (q.LegacyId IS NOT NULL)
			AND
				(
					(q.OrganisationalUnitID < 0)
				 OR (q.QuotingUserId		< 0)
				 OR (q.QuotingConsultantId	< 0)
				)
	 )
		)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	(epfvv.[Schema] = N'SSop')
			AND (epfvv.Hobt		= N'Quotes')
			AND (epfvv.Name NOT IN (N'ChaseDate2', N'ChaseDate1', N'RejectionReason', N'DateRejected', N'DateAccepted',
									N'IsFinal', N'DateSent'
								   )
				);


		IF (ISNULL (
				 (
					 SELECT SUM (qit.LineNet)
					 FROM	SSop.QuoteItemTotals AS qit
					 JOIN	SSop.QuoteItems		 AS qi ON (qi.ID = qit.ID)
					 JOIN	SSop.Quotes			 AS q ON (q.ID	 = qi.QuoteId)
					 WHERE	(q.Guid = @Guid)
						AND (qi.RowStatus NOT IN (0, 254))
				 ),
				 0
				   ) <= 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					0,
					1,
					N'A final quote must have a net value greater than 0.'
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	(epfvv.[Schema] = N'SSop')
				AND (epfvv.Hobt		= N'Quotes')
				AND (epfvv.Name		= N'IsFinal');
		END;

	END;

	

	RETURN;
END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter procedure [SSop].[EnquiryServicesExtUpsert]
--
GO








CREATE OR ALTER PROCEDURE [SSop].[EnquiryServicesExtUpsert]
	(	@DateSent DATE,
		@DateAccepted DATE,
		@DateRejected DATE,
		@DateDeclinedToQuote DATE, --[CBLD-592]
		@QuoteGuid UNIQUEIDENTIFIER,
		@Guid UNIQUEIDENTIFIER
	)
AS
BEGIN

	IF (@QuoteGuid = '00000000-0000-0000-0000-000000000000')
	BEGIN
		RETURN;
	END;

	--[CBLD-592] -Declined to quote handling.
	IF(@DateDeclinedToQuote IS NOT NULL)
	BEGIN
		UPDATE	SSop.Quotes
		SET		DateDeclinedToQuote = @DateDeclinedToQuote
		WHERE	(Guid = @QuoteGuid);

	END;

	IF (
		   @DateSent IS NOT NULL
		OR	@DateAccepted IS NOT NULL
		OR	@DateRejected IS NOT NULL
	   )
	BEGIN
		DECLARE @DeadDate DATE, 
				@IsFinal BIT, 
				@RevisionNumber INT, 
				@OrganisationalUnitGuid UNIQUEIDENTIFIER,

				@DateDeclined DATE,
				@DateDeclinedReason NVARCHAR(MAX)

		SELECT	@DeadDate = q.DeadDate, 
				@IsFinal = q.IsFinal,
				@RevisionNumber = q.RevisionNumber,
				@OrganisationalUnitGuid = ou.Guid,
				@DateDeclined = q.DateDeclinedToQuote,
				@DateDeclinedReason = q.DeclinedToQuoteReason

		FROM	SSop.Quotes AS q
		JOIN	SCore.OrganisationalUnits AS ou ON (ou.ID = q.OrganisationalUnitID)
		WHERE	(q.Guid = @QuoteGuid)

		DECLARE	@ValidationResults SCore.ValidationResult

		INSERT @ValidationResults
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
		SELECT	qv.TargetGuid, qv.TargetType, qv.IsReadOnly, qv.IsHidden, qv.IsInvalid, qv.IsInformationOnly, qv.Message
		FROM	SSop.tvf_QuotesValidate(@QuoteGuid, @DateSent, @DeadDate, @DateRejected, @IsFinal, @RevisionNumber, @OrganisationalUnitGuid, @DateDeclined, @DateDeclinedReason	) AS qv
		
		DECLARE	@ValidationMessage NVARCHAR(MAX) = SCore.GetValidationString(@ValidationResults)

		IF (@ValidationMessage <> N'')
		BEGIN			
			;THROW 60000, @ValidationMessage, 1
		END

		IF (EXISTS
				(
					SELECT	 1
					FROM	 @ValidationResults AS vr
					JOIN	SCore.EntityProperties AS ep ON (ep.Guid = vr.TargetGuid)
					WHERE	((vr.IsReadOnly = 1) OR (vr.IsHidden = 1))
						AND	(
								(ep.Name = N'DateSent' AND @DateSent IS NOT NULL)
							OR	(ep.Name = N'DateRejected' AND @DateRejected IS NOT NULL)
							OR	(ep.Name = N'DateAccepted' AND @DateAccepted IS NOT NULL)
							)
				)
			)
		BEGIN 
			;THROW 60000, N'You cannot change the Sent, Rejected or Accepted Date at the time, please check the state current of the quote.', 1
		END

		UPDATE	SSop.Quotes
		SET		DateSent = @DateSent,
				DateRejected = @DateRejected,
				DateAccepted = @DateAccepted
		WHERE	(Guid = @QuoteGuid);

	END;
END;



GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

