--
-- Create or alter view [SSop].[Enquiry_MergeInfo]
--
GO





CREATE OR ALTER VIEW [SSop].[Enquiry_MergeInfo]
AS
SELECT		e.ID,
			e.RowStatus,
			e.RowVersion,
			e.Guid AS ParentGuid,
			e.Guid AS Guid,
			e.Number																					 AS EnquiryNumber,
			e.ProposalLetter,
			e.DescriptionOfWorks,
			e.Date																						 AS EnquiryDate,
																																	/* UPRN */
			uprn.Number																					 AS UPRN,
			uprn.AddressLine1																			 AS PropertyAddressLine1,	-- was PropertyAddress1
			uprn.AddressLine2																			 AS PropertyAddressLine2,	-- was PropertyAddress2
			uprn.AddressLine3																			 AS PropertyAddressLine3,	-- was PropertyAddress3
			uprn.Town																					 AS PropertyTown,
			uprnc.Name																					 AS PropertyCounty,
			uprn.Postcode																				 AS PropertyPostcode,
			uprn.FormattedAddressComma																	 AS PropertyAddress,
			uprn.FormattedAddressCR																		 AS PropertyAddressBlock,
			COALESCE (	 uprn.Name + ' ',
						 ''
					 ) + COALESCE (	  uprn.Number + ' ',
									  ''
								  ) + uprn.AddressLine1													 AS PropertyShortAddress,
																																	/* Client */
			cacc.Name																					 AS ClientName,				-- was [Label] or [Title]
			cacc.CompanyRegistrationNumber																 AS ClientCompanyRegNo,
			cadd.AddressLine1																			 AS ClientAddressLine1,		-- was ClientAddress1
			cadd.AddressLine2																			 AS ClientAddressLine2,		-- was ClientAddress2
			cadd.AddressLine3																			 AS ClientAddressLine3,		-- was ClientAddress3
			cadd.Town																					 AS ClientTown,
			caddc.Name																					 AS ClientCounty,
			cadd.Postcode																				 AS ClientPostcode,
			cadd.FormattedAddressComma																	 AS ClientAddress,			-- was AddressClient
			cadd.FormattedAddressCR																		 AS ClientAddressBlock,
			ccon.DisplayName																			 AS ClientContactName,
			ccon.FirstName																				 AS ClientFirstName,
			ccon.Surname																				 AS ClientSurname,
			ccon.Email																					 AS ClientEmail,
			ccon.Phone																					 AS ClientPhone,
			ccon.Mobile																					 AS ClientMobile,
			aacc.Name																					 AS AgentName,				-- was [Label] or [Title]
			aacc.CompanyRegistrationNumber																 AS AgentCompanyRegNo,
			aadd.AddressLine1																			 AS AgentAddressLine1,		-- was ClientAddress1
			aadd.AddressLine2																			 AS AgentAddressLine2,		-- was ClientAddress2
			aadd.AddressLine3																			 AS AgentAddressLine3,		-- was ClientAddress3
			aadd.Town																					 AS AgentTown,
			aaddc.Name																					 AS AgentCounty,
			aadd.Postcode																				 AS AgentPostcode,
			aadd.FormattedAddressComma																	 AS AgentAddress,			-- was AddressClient
			aadd.FormattedAddressCR																		 AS AgentAddressBlock,
			acon.DisplayName																			 AS AgentContactName,
			acon.FirstName																				 AS AgentFirstName,
			acon.Surname																				 AS AgentSurname,
			acon.Email																					 AS AgentEmail,
			acon.Phone																					 AS AgentPhone,
			acon.Mobile																					 AS AgentMobile,

			facc.Name																					 AS FinanceName,				-- was [Label] or [Title]
			facc.CompanyRegistrationNumber																 AS FinanceCompanyRegNo,
			fadd.AddressLine1																			 AS FinanceAddressLine1,		-- was ClientAddress1
			fadd.AddressLine2																			 AS FinanceAddressLine2,		-- was ClientAddress2
			fadd.AddressLine3																			 AS FinanceAddressLine3,		-- was ClientAddress3
			fadd.Town																					 AS FinanceTown,
			faddc.Name																					 AS FinanceCounty,
			fadd.Postcode																				 AS FinancePostcode,
			fadd.FormattedAddressComma																	 AS FinanceAddress,			-- was AddressClient
			fadd.FormattedAddressCR																		 AS FinanceAddressBlock,
			fcon.DisplayName																			 AS FinanceContactName,
			fcon.FirstName																				 AS FinanceFirstName,
			fcon.Surname																				 AS FinanceSurname,
			fcon.Email																					 AS FinanceEmail,
			fcon.Phone																					 AS FinancePhone,
			fcon.Mobile																					 AS FinanceMobile,

			CASE
				WHEN e.SendInfoToClient = 1 THEN cacc.Name
				ELSE aacc.Name
			END																							 AS RecipientName,			-- was [Label] or [Title]
			CASE
				WHEN e.SendInfoToClient = 1 THEN cacc.CompanyRegistrationNumber
				ELSE aacc.CompanyRegistrationNumber
			END																							 AS RecipientCompanyRegNo,
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.AddressLine1
				ELSE aadd.AddressLine1
			END																							 AS RecipientAddressLine1,	-- was ClientAddress1
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.AddressLine2
				ELSE aadd.AddressLine2
			END																							 AS RecipientAddressLine2,	-- was ClientAddress2
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.AddressLine3
				ELSE aadd.AddressLine3
			END																							 AS RecipientAddressLine3,	-- was ClientAddress3
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.Town
				ELSE aadd.Town
			END																							 AS RecipientTown,
			CASE
				WHEN e.SendInfoToClient = 1 THEN caddc.Name
				ELSE aaddc.Name
			END																							 AS RecipientCounty,
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.Postcode
				ELSE aadd.Postcode
			END																							 AS RecipientPostcode,
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.FormattedAddressComma
				ELSE aadd.FormattedAddressComma
			END																							 AS RecipientAddress,		-- was AddressClient
			CASE
				WHEN e.SendInfoToClient = 1 THEN cadd.FormattedAddressCR
				ELSE aadd.FormattedAddressCR
			END																							 AS RecipientAddressBlock,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.DisplayName
				ELSE acon.DisplayName
			END																							 AS RecipientContactName,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.FirstName
				ELSE acon.FirstName
			END																							 AS RecipientFirstName,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.Surname
				ELSE ccon.Surname
			END																							 AS RecipientSurname,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.Email
				ELSE ccon.Email
			END																							 AS RecipientEmail,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.Phone
				ELSE ccon.Phone
			END																							 AS RecipientPhone,
			CASE
				WHEN e.SendInfoToClient = 1 THEN ccon.Mobile
				ELSE ccon.Mobile
			END																							 AS RecipientMobile,

																																	/* Company */
			offa.Name																					 AS OfficialName,
			offa.AddressLine1																			 AS OfficialAddressLine1,
			offa.AddressLine2																			 AS OfficialAddressLine2,
			offa.AddressLine3																			 AS OfficialAddressLine3,
			offa.Town																					 AS OfficialTown,
			offac.Name																					 AS OfficialCounty,
			offa.Postcode																				 AS OfficialPostcode,
			offcon.Email																				 AS OfficialEmail,
			offcon.Phone																				 AS OfficialPhone,
			offcon.Mobile																				 AS OfficialMobile,


																																	/* Signatory */
			sigconm.Email																				 AS SignatorytEmail,
			sig.FullName																					 AS SignatoryName,
			sig.FullName + N' ' + COALESCE (	  sigcon.PostNominals,
											  ''
										  )																 AS SignatoryPostNominals,
			sigcon.Initials																				 AS SignatoryInitials,
			sig.JobTitle																					 AS SignatoryJobTitle,
			Disciplines.TotalFee
FROM		SSop.Enquiries				  AS e
JOIN		SCore.OrganisationalUnits AS lead_ou ON (lead_ou.ID = e.OrganisationalUnitID)
LEFT JOIN		SCrm.Contact_MergeInfo	  AS offcon ON (offcon.ID = lead_ou.OfficialContactId)
LEFT JOIN		SCrm.Addresses			  AS offa ON (offa.ID = lead_ou.OfficialAddressId)
JOIN		SCrm.Counties			  AS offac ON (offac.ID = offa.CountyID)
JOIN		SJob.Properties			  AS uprn ON (uprn.ID = e.PropertyId)
JOIN		SCrm.Counties			  AS uprnc ON (uprnc.ID = uprn.CountyId)
JOIN		SCrm.Accounts			  AS cacc ON (cacc.ID = e.ClientAccountId)
JOIN		SCrm.AccountAddresses	  AS caad ON (caad.ID = e.ClientAddressId)
JOIN		SCrm.Addresses			  AS cadd ON (cadd.ID = caad.AddressID)
JOIN		SCrm.AccountContacts	  AS cac ON (cac.ID = e.ClientAccountContactId)
JOIN		SCrm.Contact_MergeInfo	  AS ccon ON (ccon.ID = cac.ContactID)
JOIN		SCrm.Counties			  AS caddc ON (caddc.ID = cadd.CountyID)
JOIN		SCrm.Accounts			  AS aacc ON (aacc.ID = e.AgentAccountId)
JOIN		SCrm.AccountAddresses	  AS aaad ON (aaad.ID = e.AgentAddressId)
JOIN		SCrm.Addresses			  AS aadd ON (aadd.ID = aaad.AddressID)
JOIN		SCrm.AccountContacts	  AS aac ON (aac.ID = e.AgentAccountContactId)
JOIN		SCrm.Contact_MergeInfo	  AS acon ON (acon.ID = aac.ContactID)
JOIN		SCrm.Counties			  AS aaddc ON (aaddc.ID = aadd.CountyID)
JOIN		SCrm.Accounts			  AS facc ON (facc.ID = e.ClientAccountId)
JOIN		SCrm.AccountAddresses	  AS faad ON (faad.ID = e.ClientAddressId)
JOIN		SCrm.Addresses			  AS fadd ON (fadd.ID = caad.AddressID)
JOIN		SCrm.AccountContacts	  AS fac ON (fac.ID = e.ClientAccountContactId)
JOIN		SCrm.Contact_MergeInfo	  AS fcon ON (fcon.ID = cac.ContactID)
JOIN		SCrm.Counties			  AS faddc ON (faddc.ID = cadd.CountyID)
JOIN		SCore.Identities		  AS sig ON (sig.ID = e.SignatoryIdentityId)
LEFT JOIN	SCrm.Contacts			  AS sigcon ON (sigcon.ID = sig.ContactId)
LEFT JOIN	SCrm.Contact_MergeInfo	  AS sigconm ON (sigconm.ID = sigcon.ID)
OUTER APPLY (
	SELECT	SUM(esei.QuoteNet) AS TotalFee
	FROM	SSop.EnquiryServices AS es
	JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.id = es.id)
	WHERE	(es.RowStatus NOT IN (0, 254))
		AND	(es.EnquiryId = e.ID)
		
) Disciplines 
		
		

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Quote_CalculatedFields]
--
GO









CREATE OR ALTER VIEW [SSop].[Quote_CalculatedFields]
   --WITH SCHEMABINDING
AS
SELECT	q.ID,
		CASE
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.QuoteItems	   AS qi
						   WHERE	(qi.QuoteId		 = q.ID)
								AND (qi.CreatedJobId > 0)
								AND	(qi.RowStatus NOT IN (0,254))
					   )
				 ) THEN N'Complete'
			WHEN q.DateDeclinedToQuote IS NOT NULL THEN N'Declined To Quote'
			WHEN q.DeadDate IS NOT NULL THEN N'Dead'
			WHEN q.DateAccepted IS NOT NULL THEN N'Accepted'
			WHEN q.DateRejected IS NOT NULL THEN N'Rejected'
			WHEN q.ExpiryDate < GETDATE () AND q.ID > 0 THEN N'Expired'
			WHEN q.DateSent IS NOT NULL THEN N'Sent'
			WHEN q.IsFinal = 1 THEN N'Ready to Send'
			ELSE N'New'
		END AS QuoteStatus
FROM	SSop.Quotes AS q
LEFT JOIN SSop.EnquiryServices AS es ON (q.EnquiryServiceID = es.ID)
LEFT JOIN SSop.Enquiries AS e ON (e.ID = es.EnquiryId);
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiryServices]
--
GO





CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiryServices]
(
	@UserId INT,
	@ParentGuid UNIQUEIDENTIFIER
)
RETURNS TABLE
             --WITH SCHEMABINDING
AS RETURN	
SELECT  es.ID,
        es.RowStatus,
        es.RowVersion,
        es.Guid,
		jt.Name AS JobType,
		q.Number AS Quote,
		esei.QuoteNet, 
		CONCAT(srs.Number, ' - ', srs.Description) AS StartRibaStage,
		CONCAT(ers.Number, ' - ', ers.Description) AS EndRibaStage,
		CASE 
			WHEN q.ID < 0 THEN N'No Quote'
			WHEN q.DateDeclinedToQuote IS NOT NULL THEN N'Declined To Quote.' --NEW [CBLD-592]
			ELSE qcf.QuoteStatus END AS QuoteStatus
FROM    SSop.EnquiryServices es
JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
JOIN	SSop.Quotes q ON (q.ID = esei.QuoteId)
JOIN	SSop.Quote_CalculatedFields AS qcf ON (qcf.ID = q.ID)
JOIN	SJob.JobTypes jt ON (jt.ID = es.JobTypeId)
JOIN	SJob.RibaStages srs ON (srs.ID = es.StartRibaStageId)
JOIN	SJob.RibaStages ers ON (ers.ID = es.EndRibaStageId)
JOIN	SSop.Enquiries enq ON (enq.ID = es.EnquiryId) --NEW [CBLD-592]
WHERE   (es.RowStatus NOT IN (0, 254))
	AND	(q.RowStatus NOT IN (0, 254))
AND	(EXISTS
			(
		SELECT
				1
		FROM
				SCore.ObjectSecurityForUser_CanRead(es.Guid, @UserId) oscr
			)
		)
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = es.EnquiryId)
			)
		)
UNION ALL
SELECT  -1,
        1,
        null,
        '00000000-0000-0000-0000-000000000000',
		N'Total:' AS JobType,
		N'' AS Quote,
		SUM(esei.QuoteNet) AS QuoteNet, 
		N'' AS StartRibaStage,
		N'' AS EndRibaStage,
		N'' AS QuoteStatus
FROM    SSop.EnquiryServices es
JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id = es.ID)
WHERE   (es.RowStatus NOT IN (0, 254))
	AND	(EXISTS 
			(
				SELECT	1
				FROM	SSop.Enquiries AS e
				WHERE	(e.Guid = @ParentGuid)
					AND	(e.ID = es.EnquiryId)
			)
		)
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SSop].[tvf_EnquiriesValidate]
--
GO

CREATE OR ALTER FUNCTION [SSop].[tvf_EnquiriesValidate]
	(
		@Guid UNIQUEIDENTIFIER,
		@RowStatus TINYINT,
		@PropertyGuid UNIQUEIDENTIFIER,
		@ClientAccountGuid UNIQUEIDENTIFIER,
		@ClientAddressGuid UNIQUEIDENTIFIER,
		@AgentAccountGuid UNIQUEIDENTIFIER,
		@AgentAddressGuid UNIQUEIDENTIFIER,
		@FinanceAccountGuid UNIQUEIDENTIFIER,
		@FinanceAddressGuid UNIQUEIDENTIFIER,
		@IsReadyForQuoteReview BIT,
		@DescriptionOfWorks NVARCHAR(MAX),
		@ValueOfWork DECIMAL(9, 2),
		@CurrentProjectRibaStageGuid UNIQUEIDENTIFIER,
		@PropertyNumber NVARCHAR(100),
		@PropertyPostCode NVARCHAR(30),
		@ClientAddressNumber NVARCHAR(100),
		@ClientAddressPostCode NVARCHAR(30),
		@AgentAddressNumber NVARCHAR(100),
		@AgentAddressPostCode NVARCHAR(30),
		@AgentName NVARCHAR(250),
		@ClientName NVARCHAR(250),
		@DeclinedToQuoteDate DATE,
		@DeclinedToQuoteReason NVARCHAR(4000),
		@KeyDates NVARCHAR(2000),
		@DeadDate DATE,
		@EnterNewClientDetails BIT,
		@EnterNewAgentDetails BIT,
		@EnterNewFinanceDetails BIT,
		@EnterNewStructureDetails BIT,
		@IsClientFinanceAccount BIT,
		@ProjectGuid UNIQUEIDENTIFIER
	)
RETURNS @ValidationResult TABLE
	(
		ID INT IDENTITY(1, 1) NOT NULL,
		TargetGuid UNIQUEIDENTIFIER NOT NULL DEFAULT ('00000000-0000-0000-0000-000000000000'),
		TargetType CHAR(1) NOT NULL DEFAULT (''),
		IsReadOnly BIT NOT NULL DEFAULT ((0)),
		IsHidden BIT NOT NULL DEFAULT ((0)),
		IsInvalid BIT NOT NULL DEFAULT ((0)),
		IsInformationOnly BIT NOT NULL DEFAULT ((0)),
		Message NVARCHAR(2000) NOT NULL DEFAULT ('')
	)
AS
BEGIN
	DECLARE @EntityPropertyGuid UNIQUEIDENTIFIER;

	/*
		Hide the NDA box once a project has been selected. 
	*/
	IF (@ProjectGuid <> '00000000-0000-0000-0000-000000000000')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'IsSubjectToNDA';
	END;

	/*
		Hide the Declinded to quote reason if there's no declined to quote date. 
	*/
	IF (@DeclinedToQuoteDate IS NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'DeclinedToQuoteReason';
	END;

	/*
		Hide the old key dates field if it wasn't populated. 
	*/
	IF (@KeyDates = N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'KeyDates';
	END;

	/*
		Ensure a reason has been given if we've declined to quote. 
	*/
	IF (@DeclinedToQuoteDate IS NOT NULL)
   AND	(@DeclinedToQuoteReason = N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				0,
				1,
				N'You must enter the reason why we declined to quote.'
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'DeclinedToQuoteReason';
	END;

	/*
		If there's both a declined to quote date and reason, lock these fields down. 
	*/
	IF (@DeclinedToQuoteDate IS NOT NULL)
   AND	(@DeclinedToQuoteReason <> N'')
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name NOT IN (N'DeclinedToQuoteDate', N'DeclinedToQuoteReason');
	END;

	/* 
		If there's a dead date. Lock everything down except that field. 
	*/
	IF (@DeadDate IS NOT NULL)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   <> N'DeadDate';
	END;

	/* Hide show manual property entry.  */
	IF (
		   @PropertyGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewStructureDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'PropertyNameNumber', N'PropertyAddressLine1', N'PropertyAddressLine2',
							   N'PropertyAddressLine3', N'PropertyTown', N'PropertyCountyId', N'PropertyPostCode',
							   N'PropertyCountryId'
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'PropertyID');
	END;

	/* Hide / Show Manual Client Entry */
	IF (
		   @ClientAccountGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewClientDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'ClientName';
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAccountID');
	END;

	/* Hide show manual client Address Entry */
	IF (
		   @ClientAddressGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewClientDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAddressNameNumber', N'ClientAddressLine1', N'ClientAddressLine2',
							   N'ClientAddressLine3', N'ClientAddressTown', N'ClientAddressCountyId',
							   N'ClientAddressPostCode', N'ClientAddressCountryId'
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'ClientAddressID', N'ClientAccountContactID');
	END;

	/* Hide Show Manual Agent Entry */
	IF (
		   @AgentAccountGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewAgentDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name	   = N'AgentName';
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAccountID');
	END;

	/* Hide show manual agent address entry */
	IF (
		   @AgentAddressGuid <> '00000000-0000-0000-0000-000000000000'
		OR	@EnterNewAgentDetails = 0
	   )
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAddressNameNumber', N'AgentAddressLine1', N'AgentAddressLine2',
							   N'AgentAddressLine3', N'AgentTown', N'AgentCountyId', N'AgentAddressPostCode',
							   N'AgentCountryId'
							  );
	END;
	ELSE
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				N'P',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'AgentAddressID', N'AgentAccountContactID');
	END;

	/* Hide show manual finance account entry */
	IF (@IsClientFinanceAccount = 1)
	BEGIN
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epg.Guid,
				N'G',
				0,
				1,
				0,
				N''
		FROM	SCore.EntityPropertyGroups AS epg
		JOIN	SCore.EntityTypes		   AS et ON (et.ID = epg.EntityTypeID)
		WHERE	(epg.Name = N'Finance Account Details')
			AND (et.Name  = N'Enquiries');
	END;
	ELSE
	BEGIN
		IF (
			   @FinanceAccountGuid <> '00000000-0000-0000-0000-000000000000'
			OR	@EnterNewFinanceDetails = 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name	   = N'FinanceAccountName';
		END;
		ELSE
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAccountID');
		END;

		IF (
			   @FinanceAddressGuid <> '00000000-0000-0000-0000-000000000000'
			OR	@EnterNewFinanceDetails = 0
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAddressNameNumber', N'FinanceAddressLine1', N'FinanceAddressLine2',
								   N'FinanceAddressLine3', N'FinanceTown', N'FinanceCountyId', N'FinancePostCode'
								  );
		END;
		ELSE
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
			SELECT	epfvv.Guid,
					N'P',
					0,
					1,
					0,
					N''
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	epfvv.[Schema] = N'SSop'
				AND epfvv.Hobt	   = N'Enquiries'
				AND epfvv.Name IN (N'FinanceAddressID', N'FinanceContactID');
		END;
	END;

	IF (@IsReadyForQuoteReview = 1)
		BEGIN
			IF (@DescriptionOfWorks = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'DescriptionOfWorks'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a description of the works.'
					 );
			END;

			IF (@ValueOfWork = 0)
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ValueOfWork'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a value of work.'
					 );
			END;

			IF (@CurrentProjectRibaStageGuid = '00000000-0000-0000-0000-000000000000')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'CurrentProjectRibaStageId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until there is a current RIBA stage.'
					 );
			END;


			IF (@PropertyGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@PropertyNumber = N'')
		   AND	(@PropertyPostCode = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'PropertyId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until property details have been entered.'
					 );
			END;

			/*
				Don't allow the enquiry to be submitted for quoting until their is a client or agent. 
			*/
			IF (@ClientAccountGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@ClientName = N'')
		   AND	(@AgentAccountGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@AgentName = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ClientAccountId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent account has been entered.'
					 );

				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'AgentAccountId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent account has been entered.'
					 );
			END;

			/*
				Don't allow the enquiry to be submitted for quoting until their is a client or agent. 
			*/
			IF (@ClientAddressGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@ClientAddressNumber = N'')
		   AND	(@ClientAddressPostCode = N'')
		   AND	(@AgentAddressGuid = '00000000-0000-0000-0000-000000000000')
		   AND	(@AgentAddressNumber = N'')
		   AND	(@AgentAddressPostCode = N'')
			BEGIN
				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'ClientAddressId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent address details have been entered.'
					 );

				SELECT	@EntityPropertyGuid = SCore.GetEntityPropertyGuid (	  N'SSop',
																			  N'Enquiries',
																			  N'AgentAddressId'
																		  );

				INSERT	@ValidationResult
					 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
				VALUES
					 (
						 @EntityPropertyGuid,
						 N'P',
						 0,
						 0,
						 1,
						 N'An enquiry cannot be reviewed until client or agent address details have been entered.'
					 );
			END;
		END;


	/*
		Check if there are quotes in existence. 
	*/
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.EnquiryServices AS es
		 JOIN	SSop.Enquiries		 AS e ON (e.ID = es.EnquiryId)
		 WHERE	(e.Guid = @Guid)
			AND (es.RowStatus NOT IN (0, 254))
			AND (EXISTS
			 (
				 SELECT 1
				 FROM	SSop.Quotes AS q
				 WHERE	(q.EnquiryServiceID = es.ID)
					AND (q.RowStatus NOT IN (0, 254))
			 )
				)
	 )
	   )
	BEGIN
		/*
			Prevent changes to 
				- Ready for Quote, ead Date and Declined to Quote date, 
				- Enquiry and Status Groups
				- Entering adhoc account or structure details. 
			after quotes have been created. 
		*/
		IF (EXISTS
		 (
			 SELECT 1
			 FROM	SSop.EnquiryServices AS es
			 JOIN	SSop.Enquiries		 AS e ON (e.ID = es.EnquiryId)
			 WHERE	(e.Guid = @Guid)
				AND (es.RowStatus NOT IN (0, 254))
		 )
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epgfvv.Guid,		-- TargetGuid - uniqueidentifier
					epgfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					0,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesGroupsForValidationV AS epgfvv
			WHERE	(epgfvv.EntityType = N'Enquiries')
				AND (epgfvv.Name NOT IN (N'Enquiry', N'Status'));

			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epfvv.Guid,			-- TargetGuid - uniqueidentifier
					epfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					1,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesForValidationV AS epfvv
			WHERE	(epfvv.[Schema] = N'SSop')
				AND (epfvv.Hobt		= N'Enquiries')
				AND (epfvv.Name IN (N'EnterNewClientDetails', N'EnterNewStructureDetails', N'EnterNewAgentDetails',
									N'EnterNewFinanceDetails'
								   )
					);
		END;

		/* If any of the quotes have reached ceertain states, don't allow the enquiry to be changed. */
		IF (EXISTS
		 (
			 SELECT 1
			 FROM	SSop.EnquiryServices			 AS es
			 JOIN	SSop.EnquiryService_ExtendedInfo AS esei ON (esei.Id	 = es.ID)
			 JOIN	SSop.Enquiries					 AS e ON (e.ID			 = es.EnquiryId)
			 JOIN	SSop.Quote_CalculatedFields		 AS qcf ON (esei.QuoteID = qcf.ID)
			 WHERE	(qcf.QuoteStatus IN (N'Sent', N'Accepted', N'Rejected', N'Complete'))
				AND (e.Guid = @Guid)
		 )
		   )
		BEGIN
			INSERT	@ValidationResult
				 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, IsInformationOnly, Message)
			SELECT	epgfvv.Guid,		-- TargetGuid - uniqueidentifier
					epgfvv.TargetType,	-- TargetType - char(1)
					1,					-- IsReadOnly - bit
					0,					-- IsHidden - bit
					0,					-- IsInvalid - bit
					0,					-- IsInformationOnly - bit
					N''					-- Message - nvarchar(2000)
			FROM	SCore.EntityPropertiesGroupsForValidationV AS epgfvv
			WHERE	(epgfvv.EntityType = N'Enquiries')
			AND (epgfvv.Name NOT IN (N'Status')) --Do not disable the "Status" group just yet.
		END;

		--Disable everything but the two chase date fields in the "Status" group
		INSERT	@ValidationResult
			 (TargetGuid, TargetType, IsReadOnly, IsHidden, IsInvalid, Message)
		SELECT	epfvv.Guid,
				epfvv.TargetType,
				1,
				0,
				0,
				N''
		FROM	SCore.EntityPropertiesForValidationV AS epfvv
		WHERE	epfvv.[Schema] = N'SSop'
			AND epfvv.Hobt	   = N'Enquiries'
			AND epfvv.Name IN (N'IsReadyForQuoteReview', N'DeclinedToQuoteDate', N'DeadDate');
	END;



	RETURN;
END;

GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SSop].[Enquiry_CalculatedFields]
--
GO







CREATE OR ALTER VIEW [SSop].[Enquiry_CalculatedFields]
   --WITH SCHEMABINDING
AS
SELECT	e.ID,
		CASE
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.QuoteItems AS qi 
											WHERE	(qi.QuoteId = q.ID)
												AND	(qi.CreatedJobId < 0)
										)
									)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = e.ID)
												AND	(q2.DateAccepted IS NULL)
												AND	(q2.DeadDate IS NULL)
												AND	(q2.DateRejected IS NULL)
										)
									)
					   )
				 ) THEN N'Complete'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND	(q2.DateAccepted IS NULL) 
												AND	(q2.DateRejected IS NULL)
												AND	(q2.DeadDate IS NULL)
										)
									)
					   )
				 ) THEN N'Accepted'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateAccepted IS NOT NULL)
								AND	(EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND	(q2.DateAccepted IS NULL) 
										)
									)
					   )
				 ) THEN N'Part Accepted'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateRejected IS NOT NULL)
								AND	(NOT EXISTS
										(
											SELECT	1
											FROM	SSop.Quotes AS q2
											JOIN	SSop.EnquiryServices es2 ON (es2.ID = q2.EnquiryServiceID)
											WHERE	(q2.ID <> q.ID)
												AND	(es2.EnquiryId = es.EnquiryID)
												AND	(q.DateRejected IS NULL) 
										)
									)
					   )
				 ) THEN N'Rejected'
			WHEN e.ChaseDate1 IS NOT NULL THEN N'1st Chase'
			WHEN e.ChaseDate2 IS NOT NULL THEN N'2nd Chase'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
								AND	(q.DateSent IS NOT NULL)
					   )
				 ) THEN N'Sent'
			WHEN (EXISTS
					   (
						   SELECT	1
						   FROM		SSop.Quotes AS q 
						   JOIN		SSop.EnquiryServices AS es ON (es.ID = q.EnquiryServiceID)
						   WHERE	(es.EnquiryId		 = e.ID)
								AND	(es.RowStatus NOT IN (0,254))
					   )
				 ) THEN N'Quoting'
			WHEN e.DeadDate IS NOT NULL THEN N'Dead'
			WHEN e.DeclinedToQuoteDate IS NOT NULL THEN N'Declined'
			WHEN e.IsReadyForQuoteReview = 1 THEN N'Ready for Quote'
			WHEN e.QuotingDeadlineDate < DATEADD(DAY, 2, GETDATE ()) THEN N'Deadline Approaching'
			WHEN e.QuotingDeadlineDate < GETDATE () THEN N'Deadline Missed'
			ELSE N'New'
		END AS EnquiryStatus
FROM	SSop.Enquiries AS e;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

