--
-- Create or alter procedure [SSop].[QuoteCreateJobs]
--
GO




CREATE OR ALTER PROCEDURE [SSop].[QuoteCreateJobs]
	(@Guid UNIQUEIDENTIFIER)
AS
BEGIN
	SET NOCOUNT ON;


	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SSop.Quotes AS q
		 WHERE	(q.Guid = @Guid)
			AND (q.DateAccepted IS NULL)
	 )
	   )
	BEGIN
		;
		THROW 60000, N'The quote must be accepted first', 1;
	END;


	PRINT N'Passed pre checks';

	/*
		  Build a consolidated list of jobs to create 
	  */
	DECLARE @JobsToCreate TABLE
		(
			ID INT NOT NULL PRIMARY KEY,
			Guid UNIQUEIDENTIFIER NOT NULL DEFAULT NEWID (),
			Net DECIMAL(19, 2) NOT NULL,
			RibaStage1Fee DECIMAL(19, 2) NOT NULL,
			RibaStage2Fee DECIMAL(19, 2) NOT NULL,
			RibaStage3Fee DECIMAL(19, 2) NOT NULL,
			RibaStage4Fee DECIMAL(19, 2) NOT NULL,
			RibaStage5Fee DECIMAL(19, 2) NOT NULL,
			RibaStage6Fee DECIMAL(19, 2) NOT NULL,
			RibaStage7Fee DECIMAL(19, 2) NOT NULL,
			PreConstructionStageFee DECIMAL(19, 2) NOT NULL,
			ConstructionStageFee DECIMAL(19, 2) NOT NULL,
			OrganisationalUnitGuid UNIQUEIDENTIFIER NOT NULL,
			JobTypeGuid UNIQUEIDENTIFIER NOT NULL,
			ContractGuid UNIQUEIDENTIFIER NOT NULL,
			IdentityGuid UNIQUEIDENTIFIER NOT NULL,
			QuoteItemId INT NOT NULL,
			ExternalReference NVARCHAR(50) NOT NULL,
			ValueOfWorkGuid UNIQUEIDENTIFIER NOT NULL,
			FeeCap DECIMAL(19, 2) NOT NULL,
			CurrentRibaStageGuid UNIQUEIDENTIFIER NOT NULL,
			TotalFee DECIMAL(19, 2) NOT NULL,
			AppointedFromStageGuid UNIQUEIDENTIFIER NOT NULL,
			CreatedJobID INT NOT NULL DEFAULT ((-1))
			
		);


	DECLARE @JobPaymentStages TABLE
		(
			Guid UNIQUEIDENTIFIER NOT NULL,
			JobId INT NOT NULL,
			StagedDate DATE NULL,
			AfterStageId INT NOT NULL,
			Value DECIMAL(19, 2) NOT NULL DEFAULT (0)
		);


	INSERT	@JobsToCreate
		 (ID,
		  Net,
		  RibaStage1Fee,
		  RibaStage2Fee,
		  RibaStage3Fee,
		  RibaStage4Fee,
		  RibaStage5Fee,
		  RibaStage6Fee,
		  RibaStage7Fee,
		  PreConstructionStageFee,
		  ConstructionStageFee,
		  OrganisationalUnitGuid,
		  JobTypeGuid,
		  ContractGuid,
		  IdentityGuid,
		  QuoteItemId,
		  ExternalReference,
		  ValueOfWorkGuid,
		  FeeCap,
		  CurrentRibaStageGuid,
		  TotalFee,
		  AppointedFromStageGuid)
	SELECT	js.ID,
			js.Net,
			js.RibaStage1Fee,
			js.RibaStage2Fee,
			js.RibaStage3Fee,
			js.RibaStage4Fee,
			js.RibaStage5Fee,
			js.RibaStage6Fee,
			js.RibaStage7Fee,
			js.PreConstructionStageFee,
			js.ConstructionStageFee,
			js.OrganisationalUnitGuid,
			js.JobTypeGuid,
			js.ContractGuid,
			js.IdentityGuid,
			js.QuoteItemId,
			js.ExternalReference,
			'00000000-0000-0000-0000-000000000000',
			js.FeeCap,
			js.CurrentRibaStageGuid,
			js.RibaStage1Fee + js.RibaStage2Fee + js.RibaStage3Fee + js.RibaStage4Fee + js.RibaStage5Fee
			+ js.RibaStage6Fee + js.RibaStage7Fee + js.PreConstructionStageFee + js.ConstructionStageFee,
			js.AppointedRibaStageGuid
	FROM	SSop.Quote_JobsSummary AS js
	WHERE	(js.QuoteGuid = @Guid)
		AND (js.DateAccepted IS NOT NULL);

	DECLARE @ClientAccountGuid	UNIQUEIDENTIFIER,
			@ClientAddressGuid	UNIQUEIDENTIFIER,
			@ClientContactGuid	UNIQUEIDENTIFIER,
			@AgentAccountGuid	UNIQUEIDENTIFIER,
			@AgentAddressGuid	UNIQUEIDENTIFIER,
			@AgentContactGuid	UNIQUEIDENTIFIER,
			@FinanceAccountGuid UNIQUEIDENTIFIER,
			@FinanceAddressGuid UNIQUEIDENTIFIER,
			@FinanceContactGuid UNIQUEIDENTIFIER,
			@StructureGuid		UNIQUEIDENTIFIER,
			@ProjectGuid		UNIQUEIDENTIFIER,
			@Overview			NVARCHAR(1000),
			@ValueOfWork		DECIMAL(19, 2);

	SELECT	@ClientAccountGuid	= ca.Guid,
			@ClientAddressGuid	= caa.Guid,
			@ClientContactGuid	= cac.Guid,
			@AgentAccountGuid	= aa.Guid,
			@AgentAddressGuid	= aaa.Guid,
			@AgentContactGuid	= aac.Guid,
			@FinanceAccountGuid = fa.Guid,
			@FinanceAddressGuid = faa.Guid,
			@FinanceContactGuid = fac.Guid,
			@StructureGuid		= p.Guid,
			@ProjectGuid		= p2.Guid,
			@Overview			= e.DescriptionOfWorks,
			@ValueOfWork		= e.ValueOfWork
	FROM	SSop.Quotes				AS q
	JOIN	SSop.Quote_ExtendedInfo AS qei ON (qei.Id = q.ID)
	JOIN	SCrm.Accounts			AS ca ON (ca.ID	  = qei.ClientAccountID)
	JOIN	SCrm.AccountAddresses	AS caa ON (caa.ID = qei.ClientAddressId)
	JOIN	SCrm.AccountContacts	AS cac ON (cac.ID = qei.ClientAccountContactId)
	JOIN	SCrm.Accounts			AS aa ON (aa.ID	  = qei.AgentAccountID)
	JOIN	SCrm.AccountAddresses	AS aaa ON (aaa.ID = qei.AgentAddressId)
	JOIN	SCrm.AccountContacts	AS aac ON (aac.ID = qei.AgentAccountContactId)
	JOIN	SCrm.Accounts			AS fa ON (fa.ID	  = qei.FinanceAccountId)
	JOIN	SCrm.AccountAddresses	AS faa ON (faa.ID = qei.FinanceAddressId)
	JOIN	SCrm.AccountContacts	AS fac ON (fac.ID = qei.FinanceContactId)
	JOIN	SJob.Properties			AS p ON (p.ID	  = qei.PropertyId)
	JOIN	SSop.Projects			AS p2 ON (p2.ID	  = q.ProjectId)
	JOIN	SSop.EnquiryServices	AS es ON (es.ID	  = q.EnquiryServiceID)
	JOIN	SSop.Enquiries			AS e ON (e.ID	  = es.EnquiryId)
	WHERE	(q.Guid = @Guid);


	DECLARE @ActiveAccountStatusID INT;

	SELECT	@ActiveAccountStatusID = ast.ID
	FROM	SCrm.AccountStatus AS ast
	WHERE	(ast.Name = N'Active');

	-- Make sure the client is active. 
	IF (EXISTS
	 (
		 SELECT 1
		 FROM	SCrm.Accounts	   AS a
		 WHERE	(a.Guid = @ClientAccountGuid)
			AND (a.AccountStatusID = @ActiveAccountStatusID)
			AND	(a.Guid <> '00000000-0000-0000-0000-000000000000')
	 )
	   )
	BEGIN
		UPDATE	SCrm.Accounts
		SET		AccountStatusID = @ActiveAccountStatusID
		WHERE	(Guid = @ClientAccountGuid);
	END;

	-- Make sure the Agent is active. 
	IF (EXISTS
	 (
		  SELECT 1
		 FROM	SCrm.Accounts	   AS a
		 WHERE	(a.Guid = @AgentAccountGuid)
			AND (a.AccountStatusID = @ActiveAccountStatusID)
			AND	(a.Guid <> '00000000-0000-0000-0000-000000000000')
	 )
	   )
	BEGIN
		UPDATE	SCrm.Accounts
		SET		AccountStatusID = @ActiveAccountStatusID
		WHERE	(Guid = @AgentAccountGuid);
	END;

	-- Make sure the Finance Account is active. 
	IF (EXISTS
	 (
		  SELECT 1
		 FROM	SCrm.Accounts	   AS a
		 WHERE	(a.Guid = @FinanceAccountGuid)
			AND (a.AccountStatusID = @ActiveAccountStatusID)
			AND	(a.Guid <> '00000000-0000-0000-0000-000000000000')
	 )
	   )
	BEGIN
		UPDATE	SCrm.Accounts
		SET		AccountStatusID = @ActiveAccountStatusID
		WHERE	(Guid = @FinanceAccountGuid);
	END;



	IF NOT EXISTS
	 (
		 SELECT 1
		 FROM	@JobsToCreate
	 )
	BEGIN
		;
		THROW 60000, N'There were no jobs to create', 1;
	END;

	/*
		  Loop through the list of jobs executing JobsUpsert
	  */
	DECLARE @CreatedDateTime		 DATETIME2 = GETUTCDATE (),
			@JobGuid				 UNIQUEIDENTIFIER,
			@OrganisationalUnitGuid	 UNIQUEIDENTIFIER,
			@JobTypeGuid			 UNIQUEIDENTIFIER,
			@ContractGuid			 UNIQUEIDENTIFIER,
			@ValueOfWorkGuid		 UNIQUEIDENTIFIER,
			@RibaStage1Fee			 DECIMAL(19, 2),
			@RibaStage2Fee			 DECIMAL(19, 2),
			@RibaStage3Fee			 DECIMAL(19, 2),
			@RibaStage4Fee			 DECIMAL(19, 2),
			@RibaStage5Fee			 DECIMAL(19, 2),
			@RibaStage6Fee			 DECIMAL(19, 2),
			@RibaStage7Fee			 DECIMAL(19, 2),
			@PreConstructionStageFee DECIMAL(19, 2),
			@ConstructionStageFee	 DECIMAL(19, 2),
			@ExternalReference		 NVARCHAR(50),
			@MaxID					 INT,
			@CurrentId				 INT,
			@QuoteItemID			 INT,
			@CreatedJobID			 INT,
			@FeeCap					 DECIMAL(19, 2),
			@CurrentRibaStageGuid	 UNIQUEIDENTIFIER,
			@AppointedRibaStageGuid	 UNIQUEIDENTIFIER;


	SELECT	@MaxID	   = MAX (ID),
			@CurrentId = 0
	FROM	@JobsToCreate;

	PRINT N'Creating job(s)';

	WHILE (@CurrentId < @MaxID)
	BEGIN
		SELECT		TOP (1) @CurrentId				 = j.ID,
							@OrganisationalUnitGuid	 = j.OrganisationalUnitGuid,
							@JobTypeGuid			 = j.JobTypeGuid,
							@ContractGuid			 = j.ContractGuid,
							@ExternalReference		 = j.ExternalReference,
							@QuoteItemID			 = j.QuoteItemId,
							@ValueOfWorkGuid		 = j.ValueOfWorkGuid,
							@RibaStage1Fee			 = j.RibaStage1Fee,
							@RibaStage2Fee			 = j.RibaStage2Fee,
							@RibaStage3Fee			 = j.RibaStage3Fee,
							@RibaStage4Fee			 = j.RibaStage4Fee,
							@RibaStage5Fee			 = j.RibaStage5Fee,
							@RibaStage6Fee			 = j.RibaStage6Fee,
							@RibaStage7Fee			 = j.RibaStage7Fee,
							@PreConstructionStageFee = j.PreConstructionStageFee,
							@ConstructionStageFee	 = j.ConstructionStageFee,
							@FeeCap					 = j.FeeCap,
							@CurrentRibaStageGuid	 = j.CurrentRibaStageGuid,
							@AppointedRibaStageGuid	 = j.AppointedFromStageGuid,
							@JobGuid				 = j.Guid
		FROM		@JobsToCreate AS j
		WHERE		(j.ID > @CurrentId)
		ORDER BY	j.ID;

		EXEC SJob.JobsUpsert @OrganisationalUnitGuid = @OrganisationalUnitGuid,				-- uniqueidentifier
							 @JobTypeGuid = @JobTypeGuid,									-- uniqueidentifier
							 @UprnGuid = @StructureGuid,									-- uniqueidentifier
							 @ClientAccountGuid = @ClientAccountGuid,						-- uniqueidentifier
							 @ClientAddressGuid = @ClientAddressGuid,
							 @ClientContactGuid = @ClientContactGuid,						-- uniqueidentifier
							 @AgentAccountGuid = @AgentAccountGuid,							-- uniqueidentifier
							 @AgentAddressGuid = @AgentAddressGuid,
							 @AgentContactGuid = @AgentContactGuid,							-- uniqueidentifier
							 @SurveyorGuid = '00000000-0000-0000-0000-000000000000',		-- uniqueidentifier
							 @JobDescription = @Overview,									-- nvarchar(1000)
							 @IsSubjectToNDA = 0,								-- bit
							 @JobStarted = @CreatedDateTime,								-- datetime2(7)
							 @JobCompleted = NULL,											-- datetime2(7)
							 @JobCancelled = NULL,											-- datetime2(7)
							 @ValueOfWorkGuid = @ValueOfWorkGuid,							-- uniqueidentifier
							 @RibaStage1Fee = @RibaStage1Fee,
							 @RibaStage2Fee = @RibaStage2Fee,
							 @RibaStage3Fee = @RibaStage3Fee,
							 @RibaStage4Fee = @RibaStage4Fee,
							 @RibaStage5Fee = @RibaStage5Fee,
							 @RibaStage6Fee = @RibaStage6Fee,
							 @RibaStage7Fee = @RibaStage7Fee,
							 @PreConstructionStageFee = @PreConstructionStageFee,
							 @ConstructionStageFee = @ConstructionStageFee,
							 @FeeCap = @FeeCap,
							 @CurrentRibaStageGuid = @CurrentRibaStageGuid,
							 @JobDormant = NULL,
							 @AgreedFee = 0,
							 @AppFormReceived = FALSE,
							 @ArchiveReferenceLink = N'',									-- nvarchar(500)
							 @ArchiveBoxReference = N'',									-- nvarchar(100)
							 @CreatedOn = @CreatedDateTime,									-- datetime2(7)
							 @ExternalReference = @ExternalReference,						-- nvarchar(50)
							 @IsCompleteForReview = 0,										-- bit
							 @ReviewedByUserGuid = '00000000-0000-0000-0000-000000000000',	-- uniqueidentifier
							 @ReviewDateTimeUTC = NULL,										-- datetime2(7)
							 @FinanceAccountGuid = @FinanceAccountGuid,
							 @FinanceAddressGuid = @FinanceAddressGuid,
							 @FinanceContactGuid = @FinanceContactGuid,
							 @PurchaseOrderNumber = N'',
							 @ContractGuid = @ContractGuid,
							 @ProjectGuid = @ProjectGuid,
							 @ValueOfWork = @ValueOfWork,
							 @ClientAppointmentReceived = 0,
							 @AppointedFromStageGuid = @AppointedRibaStageGuid,
							 @DeadDate = NULL,
							 @Guid = @JobGuid,												-- uniqueidentifier
							 @BillingInstruction = NULL;

		SELECT	@CreatedJobID = ID
		FROM	SJob.Jobs
		WHERE	(Guid = @JobGuid);

		UPDATE	@JobsToCreate
		SET		CreatedJobID = @CreatedJobID
		WHERE	(ID = @CurrentId);

		INSERT INTO @JobPaymentStages
			 (Guid, JobId, StagedDate, AfterStageId, Value)
		SELECT	sps.Guid,
				jtc.CreatedJobID,
				sps.StagedDate,
				sps.AfterStageId,
				sps.Value
		FROM	SSop.Quotes_StagedPaymentSummary (@Guid) AS sps
		JOIN	@JobsToCreate							 AS jtc ON (sps.JobId = jtc.ID)
		WHERE	(jtc.ID = @CurrentId);

		PRINT N'Created job';

		IF (@QuoteItemID > 0)
		BEGIN
			UPDATE	SSop.QuoteItems
			SET		CreatedJobId = @CreatedJobID
			WHERE	(ID = @QuoteItemID);
		END;
		ELSE
		BEGIN
			UPDATE	qi
			SET		qi.CreatedJobId = @CreatedJobID
			FROM	SSop.QuoteItems AS qi
			JOIN	SProd.Products	AS p ON (p.ID			   = qi.ProductId)
			JOIN	SJob.JobTypes	AS jt ON (p.CreatedJobType = jt.ID)
			JOIN	SSop.Quotes		AS q ON (q.ID			   = qi.QuoteId)
			WHERE	(jt.Guid				= @JobTypeGuid)
				AND (q.Guid					= @Guid)
				AND (p.NeverConsolidate		= 0)
				AND (qi.DoNotConsolidateJob = 0)
				AND (qi.RowStatus NOT IN (0, 254));
		END;

		EXEC SJob.JobActivitiesBuildFromTemplate @JobID = @CreatedJobID;
	END;

	DECLARE @GuidList SCore.GuidUniqueList,
			@IsInsert BIT;

	PRINT N'Creating staged payments';

	DELETE	FROM @GuidList;

	INSERT INTO @GuidList
		 (GuidValue)
	SELECT	Guid
	FROM	@JobPaymentStages;

	EXEC SCore.DataObjectBulkUpsert @GuidList = @GuidList,
									@SchemeName = N'SJob',
									@ObjectName = N'JobPaymentStages',
									@IsInsert = @IsInsert;


	INSERT INTO SJob.JobPaymentStages
		 (RowStatus, Guid, JobId, StagedDate, AfterStageId, Value)
	SELECT	1,
			jps.Guid,
			jps.JobId,
			jps.StagedDate,
			jps.AfterStageId,
			jps.Value
	FROM	@JobPaymentStages AS jps;


	PRINT N'Staged Payments Created';

END;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SFin].[tvf_InvoiceRequests]
--
GO





CREATE OR ALTER FUNCTION [SFin].[tvf_InvoiceRequests]
(
    @UserId INT
)
RETURNS TABLE
--WITH SCHEMABINDING
AS
RETURN SELECT ir.ID,
              ir.RowStatus,
              ir.RowVersion,
              ir.Guid,
              ir.Notes,
              ir.CreatedDateTimeUTC,
              i.Guid RequesterUserId,
              i.FullName SurveyorName,
              j.Guid JobId,
              j.Number,
              j.FinanceAccountID,
                                                                                                                              -- [CBLD-522]
              STRING_AGG(ActT.Name, ', ') ActivityID,                                                                         -- Activity name
                                                                                                                              -- [CBLD-525]
              Acc.Name ClientName,                                                                                            -- Client the request is associated with
              MAX(IRI.Net) Net,                                                                                               -- Invoice Request Amount
              MAX(Act.EndDate) EndDate,                                                                                       -- On or prior to today's date
              COALESCE(MAX(NULLIF(Acc.BillingInstruction, '')), MAX(NULLIF(j.BillingInstruction, ''))) AS BillingInstruction, -- Picks Account BillingInstruction if available, otherwise Job’s
              CASE
                  WHEN MAX(   CASE
                                  WHEN ActT.IsBillable = 0 THEN
                                      'No'
                                  ELSE
                                      'Yes'
                              END
                          ) = 'Yes' THEN
                      'Yes'
                  ELSE
                      'No'
              END AS IsBillable
       FROM SFin.InvoiceRequests ir
           JOIN SJob.Jobs j
               ON (j.ID = ir.JobId)
           JOIN SCore.Identities i
               ON (i.ID = ir.RequesterUserId)
           INNER JOIN SFin.InvoiceRequestItems AS IRI
               ON (IRI.InvoiceRequestId = ir.ID) -- NEW => [CBLD-522]
           INNER JOIN SJob.Activities AS Act
               ON (IRI.ActivityId = Act.ID) -- NEW => [CBLD-522]
           INNER JOIN SJob.ActivityTypes AS ActT
               ON (Act.ActivityTypeID = ActT.ID) -- NEW => [CBLD-522]
           INNER JOIN SCrm.Accounts AS Acc
               ON (Acc.ID = j.ClientAccountID) -- NEW => [CBLD-525]
       WHERE (ir.RowStatus NOT IN ( 0, 254 ))
             AND (ir.ID > 0)
             AND (EXISTS
       (
           SELECT 1
           FROM SFin.InvoiceRequestItems AS iri
           WHERE (iri.RowStatus NOT IN ( 0, 254 ))
                 AND (iri.InvoiceRequestId = ir.ID)
       )
                 )
             -- [CBLD-524] Completed Activity
             AND
             (
                 (EXISTS
       (
           SELECT 1
           FROM SFin.InvoiceRequestItems AS iri
               INNER JOIN SJob.Activities AS act
                   ON (iri.ActivityId = act.ID)
           WHERE (
                     act.ActivityStatusID = 3
                     OR act.ID < 0
                 )
                 AND (iri.InvoiceRequestId = ir.ID) -- Always connect back to main query
       )
                 )
                 OR (IRI.ActivityId < 0)
             )
             -- [CBLD-524] Activity must have an associated value
             AND (EXISTS
       (
           SELECT 1
           FROM SFin.InvoiceRequestItems AS iri
           WHERE (iri.RowStatus NOT IN ( 0, 254 ))
                 AND (iri.Net > 0.00)
                 AND (iri.InvoiceRequestId = ir.ID) -- Always connect back to main query
       )
                 )
             -- [CBLD-524] Activity is on or prior to today's date 
             AND
             (
                 (EXISTS
       (
           SELECT 1
           FROM SFin.InvoiceRequestItems AS iri
               INNER JOIN SJob.Activities AS Act
                   ON (iri.ActivityId = Act.ID)
           WHERE (iri.RowStatus NOT IN ( 0, 254 ))
                 AND (CAST(Act.EndDate AS DATE) <= CAST(GETDATE() AS DATE))
                 AND (iri.InvoiceRequestId = ir.ID) -- Always connect back to main query
       )
                 )
                 OR (IRI.ActivityId < 0)
             )
             AND (EXISTS
       (
           SELECT 1 FROM SCore.ObjectSecurityForUser_CanRead(j.Guid, @UserId) oscr
       )
                 )
             AND (EXISTS
       (
           SELECT 1 FROM SCore.ObjectSecurityForUser_CanRead(ir.Guid, @UserId) oscr
       )
                 )
             AND (NOT EXISTS
       (
           SELECT 1
           FROM SFin.TransactionDetails td
               INNER JOIN SFin.InvoiceRequestItems iri
                   ON (iri.ID = td.InvoiceRequestItemId)
           WHERE (iri.InvoiceRequestId = ir.ID)
       )
                 )
       GROUP BY ir.ID,
                ir.RowStatus,
                ir.RowVersion,
                ir.Guid,
                ir.Notes,
                ir.CreatedDateTimeUTC,
                i.Guid,
                i.FullName,
                j.Guid,
                j.Number,
                j.FinanceAccountID,
                ActT.Name,
                Acc.Name;
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter view [SJob].[Job_FeeDrawdown]
--
GO







CREATE OR ALTER VIEW [SJob].[Job_FeeDrawdown] 
	   --WITH SCHEMABINDING
AS SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		CASE
				WHEN rs.Number = -1 THEN
					N'Fee Cap'
				ELSE
				CONVERT(NVARCHAR(10),
				rs.Number
				)
		END	  AS Stage,
		CASE
				WHEN rs.Number = -1 THEN
					N'Fee Cap'
				ELSE
				rs.Description
		END	  AS StageLabel,
		CASE rs.Number
				WHEN N'0' THEN
					(0 + ISNULL(Amendments.Stage0Change,
					0
					)
					)
				WHEN N'1' THEN
					(j.RibaStage1Fee + ISNULL(Amendments.Stage1Change,
					0
					)
					)
				WHEN N'2' THEN
					(j.RibaStage2Fee + ISNULL(Amendments.Stage2Change,
					0
					)
					)
				WHEN N'3' THEN
					(j.RibaStage3Fee + ISNULL(Amendments.Stage3Change,
					0
					)
					)
				WHEN N'4' THEN
					(j.RibaStage4Fee + ISNULL(Amendments.Stage4Change,
					0
					)
					)
				WHEN N'5' THEN
					(j.RibaStage5Fee + ISNULL(Amendments.Stage5Change,
					0
					)
					)
				WHEN N'6' THEN
					(j.RibaStage6Fee + ISNULL(Amendments.Stage6Change,
					0
					)
					)
				WHEN N'7' THEN
					(j.RibaStage7Fee + ISNULL(Amendments.Stage7Change,
					0
					)
					)
				WHEN N'99' THEN
					(j.PreConstructionStageFee + ISNULL(Amendments.PreConstructionStageChange,
					0
					)
					)
				WHEN N'999' THEN
					(j.ConstructionStageFee + ISNULL(Amendments.ConstructionStageChange,
					0
					)
					)
				ELSE
				(j.FeeCap + ISNULL(Amendments.FeeCapChange,
				0
				)
				)
		END	  AS Agreed,
		SUM(ISNULL(td.Net,
		0
		))	  AS Invoiced,
		CASE rs.Number
				WHEN N'0' THEN
					0
				WHEN N'1' THEN
					j.RibaStage1Fee
				WHEN N'2' THEN
					j.RibaStage2Fee
				WHEN N'3' THEN
					j.RibaStage3Fee
				WHEN N'4' THEN
					j.RibaStage4Fee
				WHEN N'5' THEN
					j.RibaStage5Fee
				WHEN N'6' THEN
					j.RibaStage6Fee
				WHEN N'7' THEN
					j.RibaStage7Fee
				ELSE
				j.FeeCap
		END - SUM(ISNULL(td.Net,
		0
		))	  AS Remaining,

		-- QUOTEDMEETINGS
		CASE 
			WHEN rs.Number = N'0'  THEN 
				CASE 
					WHEN (Amendments.Stage0MeetingChange IS NULL OR Amendments.Stage0MeetingChange = 0) 
						--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							 FROM SSop.QuoteItems qi
							 WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 1),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage0MeetingChange) AS INT)
				END
			WHEN rs.Number = N'1' THEN 
				CASE 
					WHEN (Amendments.Stage1MeetingChange IS NULL OR Amendments.Stage1MeetingChange = 0) 
						--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							 FROM SSop.QuoteItems qi
							 WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 2),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage1MeetingChange) AS INT)
				END
			WHEN rs.Number = N'2'  THEN 
				CASE 
					WHEN (Amendments.Stage2MeetingChange IS NULL OR Amendments.Stage2MeetingChange = 0) 
						--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							 FROM SSop.QuoteItems qi
							 WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 3),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage2MeetingChange) AS INT)
				END
			WHEN rs.Number = N'3'  THEN 
			CASE 
				WHEN (Amendments.Stage3MeetingChange IS NULL OR Amendments.Stage3MeetingChange = 0) 
					--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
					THEN CAST(
						ISNULL((SELECT ISNULL(qi.NumberOfMeetings, 0)
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 4),0)
					AS INT)
					ELSE 
						CAST(SUM(Amendments.Stage3MeetingChange) AS INT)
				END
			WHEN rs.Number = N'4' THEN 
			CASE
				WHEN (Amendments.Stage4MeetingChange IS NULL OR Amendments.Stage4MeetingChange = 0) 
					--THEN CAST(SUM(ISNULL(qi.NumberOfMeetings, 0)) AS INT)
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 5),0)
					AS INT)
					ELSE 
						CAST(SUM(Amendments.Stage4MeetingChange) AS INT)
				END
			WHEN rs.Number = N'5'  THEN
				CASE 
					WHEN (Amendments.Stage5MeetingChange IS NULL OR Amendments.Stage5MeetingChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 7),0)
					AS INT)
					ELSE 
						CAST(SUM(Amendments.Stage5MeetingChange) AS INT)
				END
			WHEN rs.Number = N'6'  THEN 
				CASE 
					WHEN (Amendments.Stage6MeetingChange IS NULL OR Amendments.Stage6MeetingChange = 0) 
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
								FROM SSop.QuoteItems qi
								WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 8), 0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage6MeetingChange) AS INT)
				END
			WHEN rs.Number = N'7'  THEN 
				CASE 
					WHEN (Amendments.Stage7MeetingChange IS NULL OR Amendments.Stage7MeetingChange = 0) 
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
								FROM SSop.QuoteItems qi
								WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 9),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.Stage7MeetingChange) AS INT)
				END
			-- PRECONSTRUCTION
			WHEN rs.Number = N'99'  THEN 
				CASE 
					WHEN (Amendments.PreConstructionStageMeetingChange IS NULL OR Amendments.PreConstructionStageMeetingChange = 0)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
								FROM SSop.QuoteItems qi
								WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 10),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.PreConstructionStageMeetingChange) AS INT)
				END
			-- CONSTRUCTION
			WHEN rs.Number = N'999' THEN
				CASE 
					WHEN (Amendments.ConstructionStageMeetingChange IS NULL OR Amendments.ConstructionStageMeetingChange = 0)
						THEN CAST(
							ISNULL((SELECT SUM(ISNULL(qi.NumberOfMeetings, 0))
								FROM SSop.QuoteItems qi
								WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 10),0)
						AS INT)
						ELSE 
							CAST(SUM(Amendments.ConstructionStageMeetingChange) AS INT)
				END
			ELSE SUM(ISNULL(qs.NumberOfMeetings,0))
		END AS QuotedMeetings,

		ISNULL(Meetings.MeetingTotal,
		0
		)	  AS CompletedMeetings,

		-- QUOTEDSITEVISITS
		CASE 
			WHEN rs.Number = N'0'  THEN 
				CASE 
					WHEN (Amendments.Stage0VisitChange IS NULL OR Amendments.Stage0VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 1),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage0VisitChange) AS INT)
				END
			WHEN rs.Number = N'1'  THEN 
				CASE 
					WHEN (Amendments.Stage1VisitChange IS NULL OR Amendments.Stage1VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 2),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage1VisitChange) AS INT)
				END
			WHEN rs.Number = N'2'  THEN 
				CASE  
					WHEN (Amendments.Stage2VisitChange IS NULL OR Amendments.Stage2VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 3),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage2VisitChange) AS INT)
				END
			WHEN rs.Number = N'3'  THEN 
				CASE 
					WHEN (Amendments.Stage3VisitChange IS NULL OR Amendments.Stage3VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 4),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage3VisitChange) AS INT)
				END
			WHEN rs.Number = N'4'   THEN 
				CASE 
					WHEN (Amendments.Stage4VisitChange IS NULL OR Amendments.Stage4VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 5),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage4VisitChange) AS INT)
				END

			WHEN rs.Number = N'5'  THEN
				CASE 
					WHEN (Amendments.Stage5VisitChange IS NULL OR Amendments.Stage5VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 7),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage5VisitChange) AS INT)
				END
			WHEN rs.Number = N'6'  THEN 
				CASE 
					WHEN (Amendments.Stage6VisitChange IS NULL OR Amendments.Stage6VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 8),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage6VisitChange) AS INT)
				END
			WHEN rs.Number = N'7'  THEN 
				CASE 
					WHEN (Amendments.Stage7VisitChange IS NULL OR Amendments.Stage7VisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 9),0)
					AS INT)
					ELSE CAST(SUM(Amendments.Stage7VisitChange) AS INT)
				END
			-- PRECONSTRUCTION
			WHEN rs.Number = N'99'   THEN 
			    CASE 
					WHEN (Amendments.PreConstructionStageVisitChange IS NULL OR Amendments.PreConstructionStageVisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 10),0)
					AS INT)
					ELSE CAST(SUM(Amendments.PreConstructionStageVisitChange) AS INT)
				END
			-- CONSTRUCTION
			WHEN rs.Number = N'999'  THEN
				CASE 
					WHEN (Amendments.ConstructionStageVisitChange IS NULL OR Amendments.ConstructionStageVisitChange = 0) 
					THEN CAST(
						ISNULL((SELECT SUM(ISNULL(qi.NumberOfSiteVisits, 0))
							FROM SSop.QuoteItems qi
							WHERE qi.CreatedJobId = j.ID AND qi.ProvideAtStageID = 11),0)
					AS INT)
					ELSE CAST(SUM(Amendments.ConstructionStageVisitChange) AS INT)
				END
			ELSE SUM(ISNULL(qs.NumberOfSiteVisits,0))
		END AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		)	  AS CompletedSiteVisits,
		j.ID  AS JobId,
		rs.ID AS StageId
FROM
		SJob.Jobs AS j
CROSS JOIN
		SJob.RibaStages AS rs
LEFT JOIN
		SJob.Activities AS a ON (a.RibaStageId = rs.ID)
				AND (a.JobId = j.ID)
				AND	(a.RowStatus NOT IN (0, 254))
OUTER APPLY
		(
			SELECT
					td.Net *
							CASE
									WHEN tt.IsNegated = 1 THEN
										-1
									ELSE
									1
							END AS Net
			FROM
					SFin.TransactionDetails AS td
			JOIN
					SFin.Transactions AS t ON (t.ID = td.TransactionID)
			JOIN
					SFin.TransactionTypes AS tt ON (tt.ID = t.TransactionTypeID)
			WHERE
					(td.ActivityID = a.ID)
					AND (tt.IsBank = 0)
					AND (td.RowStatus NOT IN (0, 254))
					AND (t.RowStatus NOT IN (0, 254))
		) AS td
LEFT JOIN
		SSop.QuoteItems AS qi ON (qi.CreatedJobId = j.ID)
			AND (qi.RowStatus NOT IN (0, 254))
LEFT JOIN
		SSop.QuoteSections AS qs ON (qs.ID = qi.QuoteSectionId)
				AND (qs.RibaStageId = rs.ID)
OUTER APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change)		   AS Stage0Change,
					SUM(fa.RibaStage1Change)		   AS Stage1Change,
					SUM(fa.RibaStage2Change)		   AS Stage2Change,
					SUM(fa.RibaStage3Change)		   AS Stage3Change,
					SUM(fa.RibaStage4Change)		   AS Stage4Change,
					SUM(fa.RibaStage5Change)		   AS Stage5Change,
					SUM(fa.RibaStage6Change)		   AS Stage6Change,
					SUM(fa.RibaStage7Change)		   AS Stage7Change,
					SUM(fa.PreConstructionStageChange) AS PreConstructionStageChange,
					SUM(fa.ConstructionStageChange)	   AS ConstructionStageChange,
					SUM(fa.FeeCapChange)			   AS FeeCapChange,

					SUM(fa.RibaStage0VisitChange)      AS Stage0VisitChange,
					SUM(fa.RibaStage1VisitChange)      AS Stage1VisitChange,
					SUM(fa.RibaStage2VisitChange)      AS Stage2VisitChange,
					SUM(fa.RibaStage3VisitChange)      AS Stage3VisitChange,
					SUM(fa.RibaStage4VisitChange)      AS Stage4VisitChange,
					SUM(fa.RibaStage5VisitChange)      AS Stage5VisitChange,
					SUM(fa.RibaStage6VisitChange)      AS Stage6VisitChange,
					SUM(fa.RibaStage7VisitChange)      AS Stage7VisitChange,

					SUM(fa.RibaStage0MeetingChange)    AS Stage0MeetingChange,
					SUM(fa.RibaStage1MeetingChange)    AS Stage1MeetingChange,
					SUM(fa.RibaStage2MeetingChange)    AS Stage2MeetingChange,
					SUM(fa.RibaStage3MeetingChange)    AS Stage3MeetingChange,
					SUM(fa.RibaStage4MeetingChange)    AS Stage4MeetingChange,
					SUM(fa.RibaStage5MeetingChange)    AS Stage5MeetingChange,
					SUM(fa.RibaStage6MeetingChange)    AS Stage6MeetingChange,
					SUM(fa.RibaStage7MeetingChange)    AS Stage7MeetingChange,

					SUM(fa.PreConstructionStageMeetingChange) 	  AS PreConstructionStageMeetingChange,
					SUM(fa.PreConstructionStageVisitChange)		  AS PreConstructionStageVisitChange,
					SUM(fa.ConstructionStageMeetingChange)		  AS ConstructionStageMeetingChange, 
					SUM(fa.ConstructionStageVisitChange)		  AS ConstructionStageVisitChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
					AND (ja.RibaStageId = rs.ID)
		) AS Meetings
WHERE
		(rs.ID > 0)
		AND (
				(
						(rs.IsRealStage = 1)
						AND (
								(j.PreConstructionStageFee = 0)
								AND (j.ConstructionStageFee = 0)
						)
				)
				OR (
						(rs.IsRealStage = 0)
						AND (
								(j.PreConstructionStageFee <> 0)
								OR (j.ConstructionStageFee <> 0)
						)
				)
		)
GROUP BY
		rs.Number,
		rs.Description,
		rs.ID,
		j.RibaStage1Fee,
		j.RibaStage2Fee,
		j.RibaStage3Fee,
		j.RibaStage4Fee,
		j.RibaStage5Fee,
		j.RibaStage6Fee,
		j.RibaStage7Fee,
		j.PreConstructionStageFee,
		j.ConstructionStageFee,
		j.FeeCap,
		j.RowStatus,
		j.Guid,
		j.ID,
		Amendments.Stage0Change,
		Amendments.Stage1Change,
		Amendments.Stage2Change,
		Amendments.Stage3Change,
		Amendments.Stage4Change,
		Amendments.Stage5Change,
		Amendments.Stage6Change,
		Amendments.Stage7Change,
		--NEW
		Amendments.Stage0MeetingChange,
		Amendments.Stage1MeetingChange,
		Amendments.Stage2MeetingChange,
		Amendments.Stage3MeetingChange,
		Amendments.Stage4MeetingChange,
		Amendments.Stage5MeetingChange,
		Amendments.Stage6MeetingChange,
		Amendments.Stage7MeetingChange,
		--NEW
		Amendments.Stage0VisitChange,
		Amendments.Stage1VisitChange,
		Amendments.Stage2VisitChange,
		Amendments.Stage3VisitChange,
		Amendments.Stage4VisitChange,
		Amendments.Stage5VisitChange,
		Amendments.Stage6VisitChange,
		Amendments.Stage7VisitChange,

		Amendments.PreConstructionStageChange,
		Amendments.ConstructionStageChange,
		--NEW
		Amendments.PreConstructionStageMeetingChange,
		Amendments.PreConstructionStageVisitChange,
		Amendments.ConstructionStageMeetingChange,
		Amendments.ConstructionStageVisitChange,

		Amendments.FeeCapChange,
		Meetings.MeetingTotal,
		Meetings.SiteVisitTotal
UNION ALL
SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		N'Total (ex. Fee Cap.)',
		N'Total (ex. Fee Cap.)',
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee
		+ ISNULL(Amendments.TotalChange,
		0
		),
		ISNULL(jf.InvoicedValue,
		0
		),
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee
		+ ISNULL(Amendments.TotalChange,
		0
		) - ISNULL(jf.InvoicedValue,
		0
		),
		ISNULL(Quoted.Meetings,
		0
		) AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		) AS CompletedMeetings,
		ISNULL(Quoted.SiteVisits,
		0
		) AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		) AS CompletedSiteVisits,
		j.ID,
		-2
FROM
		SJob.Jobs AS j
LEFT JOIN
		SJob.JobFinance AS jf ON (jf.ID = j.ID)
CROSS APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change
					+ fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.PreConstructionStageChange
					+ fa.ConstructionStageChange
					) AS TotalChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
		) AS Meetings
OUTER APPLY
		(
			SELECT
					SUM(qs.NumberOfMeetings)   Meetings,
					SUM(qs.NumberOfSiteVisits) SiteVisits
			FROM
					SSop.QuoteItems AS qi
			LEFT JOIN
					SSop.QuoteSections AS qs ON (qs.ID = qi.QuoteSectionId)
			WHERE
					(qi.CreatedJobId = j.ID)
		) AS Quoted
UNION ALL
SELECT
		j.ID,
		j.RowStatus,
		j.Guid,
		N'Total (inc. Fee Cap)',
		N'Total (inc. Fee Cap)',
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee + j.FeeCap
		+ ISNULL(Amendments.TotalChange,
		0
		),
		ISNULL(jf.InvoicedValue,
		0
		),
		j.AgreedFee + j.PreConstructionStageFee + j.ConstructionStageFee + j.RibaStage1Fee + j.RibaStage2Fee
		+ j.RibaStage3Fee + j.RibaStage4Fee + j.RibaStage5Fee + j.RibaStage6Fee + j.RibaStage7Fee + j.FeeCap
		+ ISNULL(Amendments.TotalChange,
		0
		) - ISNULL(jf.InvoicedValue,
		0
		),
		ISNULL(Quoted.Meetings,
		0
		) AS QuotedMeetings,
		ISNULL(Meetings.MeetingTotal,
		0
		) AS CompletedMeetings,
		ISNULL(Quoted.SiteVisits,
		0
		) AS QuotedSiteVisits,
		ISNULL(Meetings.SiteVisitTotal,
		0
		) AS CompletedSiteVisits,
		j.ID,
		-3
FROM
		SJob.Jobs AS j
LEFT JOIN
		SJob.JobFinance AS jf ON (jf.ID = j.ID)
CROSS APPLY
		(
			SELECT
					SUM(fa.RibaStage0Change + fa.RibaStage1Change + fa.RibaStage2Change + fa.RibaStage3Change + fa.RibaStage4Change
					+ fa.RibaStage5Change + fa.RibaStage6Change + fa.RibaStage7Change + fa.PreConstructionStageChange
					+ fa.ConstructionStageChange + fa.FeeCapChange
					) AS TotalChange
			FROM
					SJob.FeeAmendment AS fa
			WHERE
					(fa.RowStatus NOT IN (0, 254))
					AND (fa.JobId = j.ID)
		) AS Amendments
OUTER APPLY
		(
			SELECT
					SUM(CASE
							WHEN jat.IsMeeting = 1 THEN
								1
							ELSE
							0
					END
					) AS MeetingTotal,
					SUM(CASE
							WHEN jat.IsSiteVisit = 1 THEN
								1
							ELSE
							0
					END
					) AS SiteVisitTotal
			FROM
					SJob.Activities AS ja
			JOIN
					SJob.ActivityTypes AS jat ON (jat.ID = ja.ActivityTypeID)
			JOIN
					SJob.ActivityStatus AS jas ON (jas.ID = ja.ActivityStatusID)
			WHERE
					(ja.JobId = j.ID)
					AND (jas.Name = N'Complete')
					AND (ja.RowStatus NOT IN (0, 254))
					AND (
							(jat.IsMeeting = 1)
							OR (jat.IsSiteVisit = 1)
					)
		) AS Meetings
OUTER APPLY
		(
			SELECT
					-- CBLD-587
					--SUM(qs.NumberOfMeetings)   Meetings,
					--SUM(qs.NumberOfSiteVisits) SiteVisits
					SUM(qi.NumberOfMeetings)   Meetings,
					SUM(qi.NumberOfSiteVisits) SiteVisits

			FROM
					SSop.QuoteItems AS qi
			JOIN
					SSop.QuoteSections AS qs ON (qs.ID = qi.QuoteSectionId)
			WHERE
					(qi.CreatedJobId = j.ID)
				AND	(qi.RowStatus NOT IN (0, 254))
		) AS Quoted
GO
IF @@ERROR<>0 OR @@TRANCOUNT=0 BEGIN IF @@TRANCOUNT>0 ROLLBACK SET NOEXEC ON END
GO

--
-- Create or alter function [SJob].[Activities_DataPills]
--
GO



CREATE OR ALTER FUNCTION [SJob].[Activities_DataPills]
  (
	@SurveyorGuid				UNIQUEIDENTIFIER,
	@BillableHours				DECIMAL(19,2),
	@JobGuid					UNIQUEIDENTIFIER,
	@RibaStageGuid				UNIQUEIDENTIFIER,
	@IsAdditionalWork			BIT,
	@Guid						UNIQUEIDENTIFIER
	
  )
RETURNS @DataPills TABLE
  (
    [ID]        [INT]        IDENTITY (1, 1) NOT NULL,
    [Label]     NVARCHAR(50) NOT NULL,
    [Class]     NVARCHAR(50) NOT NULL,
    [SortOrder] INT          NOT NULL
  )
AS
  BEGIN
    DECLARE @JobID INT,
			@JobUsesTimeSheets BIT,
			@StageInvoiced DECIMAL(19,2) = 0,
			@StageQuoted DECIMAL (19,2) = 0,
			@BillableValue DECIMAL(19,2) = 0,
			@BillableRate DECIMAL(19,2) = 0

	SELECT
			@JobUsesTimeSheets = jt.UseTimeSheets
	FROM
			SJob.JobTypes jt
	WHERE
			(EXISTS
				(
					SELECT
							1
					FROM
							SJob.Jobs j
					WHERE
							(j.JobTypeID = jt.ID)
							AND (j.Guid = @JobGuid)
				)
			)

	
	-- Data pill for billable/non-billable activities.
	IF (EXISTS
			(
				SELECT *
				FROM SJob.Activities AS Act
				JOIN SJob.Jobs AS J ON (Act.JobID = J.ID)
				JOIN SJob.ActivityTypes ActT ON (ActT.ID = Act.ActivityTypeID)
				WHERE J.Guid = @JobGuid AND ActT.IsBillable = 1 AND AcT.Guid = @Guid
			)	
		)
	BEGIN
		INSERT @DataPills
			  (
				Label,
				Class,
				SortOrder
			  )
		VALUES
			  (
				N'Billable Activity',	-- Label - nvarchar(50)
				N'bg-info',	-- Class - nvarchar(50)
				1		-- SortOrder - int
			  )
	END
	ELSE
	BEGIN
		INSERT @DataPills
			  (
				Label,
				Class,
				SortOrder
			  )
		VALUES
			  (
				N'Non-Billable Activity',	-- Label - nvarchar(50)
				N'bg-info',	-- Class - nvarchar(50)
				2		-- SortOrder - int
			  )
	END

	




	IF (@JobUsesTimeSheets = 1)
	BEGIN
		IF (@IsAdditionalWork = 0)
		BEGIN
			SELECT
					@StageInvoiced = jfd.Invoiced,
					@StageQuoted   = jfd.Agreed
			FROM
					SJob.Job_FeeDrawdown jfd
			JOIN
					SJob.Jobs j ON (j.ID = jfd.JobID)
			JOIN
					SJob.RibaStages rs ON (rs.ID = jfd.StageId)
			WHERE
					(j.Guid = @JobGuid)
					AND (rs.Guid = @RibaStageGuid)
		END
		ELSE
		BEGIN
			SELECT
					@StageInvoiced = ISNULL(jfd.Invoiced, 0),
					@StageQuoted   = ISNULL(jfd.Agreed, 0)
			FROM
					SJob.Jobs j
			LEFT JOIN
					SJob.Job_FeeDrawdown jfd ON (j.ID = jfd.JobID)
			WHERE
					(j.Guid = @JobGuid)
					AND (ISNULL(jfd.StageId, -1) = -1)
		END

		SELECT
				@BillableValue = BillableRate * @BillableHours,
				@BillableRate  = BillableRate
		FROM
				SCore.Identities
		WHERE
				(Guid = @SurveyorGuid)

		IF (@BillableRate = 0
			AND
			@BillableHours <> 0)
		BEGIN
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'The assignee has no billable rate; work is FoC',	-- Label - nvarchar(50)
						N'bg-info',	-- Class - nvarchar(50)
						1		-- SortOrder - int
					)
		END

		IF ((@StageInvoiced + @BillableValue) > @StageQuoted)
		BEGIN
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'The quoted value for this stage has been exceeded',	-- Label - nvarchar(50)
						N'bg-danger',	-- Class - nvarchar(50)
						1		-- SortOrder - int
					)
		END

		IF (CASE
					WHEN @StageQuoted > 0 THEN
						(@StageInvoiced / @StageQuoted)
					ELSE
					0
			END > 0.9)
		BEGIN
			INSERT @DataPills
					(
						Label,
						Class,
						SortOrder
					)
			VALUES
					(
						N'Over 90% of the quoted value used in this stage',	-- Label - nvarchar(50)
						N'bg-warning',	-- Class - nvarchar(50)
						1		-- SortOrder - int
					)
		END
	END;

	RETURN
END
